#nullable enable // autogenerated

using System;
using MVZ2.Models;
using MVZ2.View.Level;
using MVZ2Logic.Inputs;
using PVZEngine.Buffs;
using UnityEngine;
using UnityEngine.EventSystems;

namespace MVZ2.Grids
{
    public class GridView : MonoBehaviour
    {
        #region 生命周期
        private void Awake()
        {
            holdStreakHandler.OnPointerInteraction += (_, d, i) => OnPointerInteraction?.Invoke(this, d, i);
        }
        public void UpdateFixed()
        {
            holdStreakHandler.UpdateHoldAndStreak();
            if (model.Exists())
            {
                model.UpdateFixed();
            }
        }
        public void UpdateFrame(float deltaTime)
        {
            if (model.Exists())
            {
                model.UpdateFrame(deltaTime);
                model.UpdateAnimators(deltaTime);
            }
        }
        #endregion

        #region 模型
        public void BuildModel(IModelBuilder builder)
        {
            if (model.Exists())
            {
                Destroy(model.gameObject);
            }
            model = builder.Build(modelRoot);
        }
        public Model? GetModel()
        {
            return model;
        }
        public void UpdateModelInsertions(ModelInsertion[] modelInsertions)
        {
            if (model.Exists())
                model.UpdateModelInsertions(modelInsertions);
        }
        #endregion

        #region 设置属性
        public void SetModelSortingLayerAndOrder(string layer, int order)
        {
            if (model.Exists() && model is EntityModel entityModel)
            {
                entityModel.SortingLayerName = layer;
                entityModel.SortingOrder = order;
            }
        }
        public int GetSortingLayerID()
        {
            return spriteRenderer.sortingLayerID;
        }
        public int GetSortingOrder()
        {
            return spriteRenderer.sortingOrder;
        }
        public void SetPosition(Vector3 position)
        {
            transform.localPosition = position;
        }
        public void SetSprite(Sprite? sprite)
        {
            spriteRenderer.sprite = sprite;
        }
        public void SetColor(Color color)
        {
            spriteRenderer.color = color;
        }
        public void SetDisplaySection(float start, float end, Vector2 size, float bevelHeight)
        {
            var sprSize = spriteRenderer.size;
            sprSize.y = (end - start) * size.y + Mathf.Abs(bevelHeight);
            spriteRenderer.size = sprSize;

            var pos = rendererTransform.localPosition;
            pos.y = (end - 1) * size.y;
            rendererTransform.localPosition = pos;
        }
        public void SetColliderBevel(Vector2 size, float height)
        {
            var points = polygonCollider.points;
            if (points.Length >= 4)
            {
                points[2].y = -size.y * 0.5f - height;
                points[3].y = size.y * 0.5f - height;
                polygonCollider.points = points;
            }
        }
        #endregion

        public event Action<GridView, PointerEventData, PointerInteraction>? OnPointerInteraction;
        [SerializeField]
        private Transform rendererTransform = null!;
        [SerializeField]
        private SpriteRenderer spriteRenderer = null!;
        [SerializeField]
        private LevelPointerInteractionHandler holdStreakHandler = null!;
        [SerializeField]
        private PolygonCollider2D polygonCollider = null!;
        [SerializeField]
        private Transform modelRoot = null!;
        private Model? model = null;
    }
}
